        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Overall survival (OS)",
              "description": "OS will be compared between arms and within the subgroups defined by the stratification factors and by PD-L1 subgroups. Distributions of OS will be estimated using the method of Kaplan-Meier. Hazard ratios for comparisons of OS will be estimated using a Cox Proportional Hazards regression model, with baseline hazard stratification using the stratification factors. Testing will be done using a stratified log-rank test. Confidence intervals (CIs) about medians will be estimated using the method of Brookmeyer-Crowley. For point estimates at landmark times, the associated CIs will be calculated using Greenwood's formula and based on a log-log transformation applied on the survival function.",
              "timeFrame": "From date of randomization to date of death due to any cause, assessed up to 3 years"
            }
          ],
          "secondaryOutcomes": [
            {
              "measure": "Progression-free survival (PFS)",
              "description": "PFS will be compared between arms and within the subgroups defined by the stratification factors and by PD-L1 subgroups. PFS between the arms will be assessed using Response Evaluation Criteria in Solid Tumors (RECIST) 1.1. Distributions of PFS will be estimated using the method of Kaplan-Meier. Hazard ratios for comparisons of PFS will be estimated using a Cox Proportional Hazards regression model, with baseline hazard stratification using the stratification factors. Testing will be done using a stratified log-rank test. CIs about medians will be estimated using the method of Brookmeyer-Crowley. For point estimates at landmark times, the associated CIs will be calculated using Greenwood's formula and based on a log-log transformation applied on the survival function.",
              "timeFrame": "From date of randomization to date of first documentation of progression, symptomatic deterioration, or death, whichever comes first, assessed up to 3 years"
            },
            {
              "measure": "Response rates",
              "description": "Response rates (complete response \\[CR\\] or partial response \\[PR\\]) between the arms will be assessed per RECIST 1.1. Binary proportions along with confidence intervals will be estimated for response. CIs will be estimated using the Wilson Score method with continuity correction.",
              "timeFrame": "Up to 3 years"
            },
            {
              "measure": "Disease control rates",
              "description": "Disease control rates (CR or PR and stable disease) between the arms. Binary proportions along with confidence intervals will be estimated for disease control rate. CIs will be estimated using the Wilson Score method with continuity correction.",
              "timeFrame": "Up to 3 years"
            },
            {
              "measure": "Duration of response (DOR)",
              "description": "Will be assessed among participants who achieve a response. Distributions of DOR will be estimated using the method of Kaplan-Meier.",
              "timeFrame": "From date of first documentation of response by RECIST 1.1 (CR or PR, confirmed or unconfirmed) to date of first documentation of progression or symptomatic deterioration, or death due to any cause, assessed up to 3 years"
            },
            {
              "measure": "Incidence of adverse events",
              "description": "Adverse events will be assessed and graded using Common Terminology Criteria for Adverse Events version 5.0. Individual toxicities within each treatment arm will be summarized by grade, among those reported as being attributable to treatment (possibly, probably, or definitely attributable to treatment). The frequency and severity for each adverse event term will be summarized for grade 3, 4 and 5 separately, and as worst grade reported overall all reported adverse events.",
              "timeFrame": "Up to 90 days after last dose of study treatment"
            }
          ],
          "otherOutcomes": [
            {
              "measure": "Cell-free deoxyribonucleic acid",
              "timeFrame": "At baseline, cycle 3 day 1 and at progression up to 3 years (each cycle is 21 days)"
            },
            {
              "measure": "Tissue/blood repository",
              "timeFrame": "Up to 3 years"
            }
          ]
